import{_ as a,c as t,a as o,o as i}from"./app-DC1MrdO1.js";const n={};function s(h,e){return i(),t("div",null,[...e[0]||(e[0]=[o('<h2 id="p301-310" tabindex="-1"><a class="header-anchor" href="#p301-310"><span>P301-310</span></a></h2><h3 id="_301-the-weekend-vampires" tabindex="-1"><a class="header-anchor" href="#_301-the-weekend-vampires"><span>[301] The Weekend - Vampires</span></a></h3><p>A: You want to go tothe movies tonight?</p><p>B: Sure! What’s playing?</p><p>A: The new Twilight movie!</p><p>B: Twilight? As inthe vampire movies? No way I am watching that. I don’t understand why everyone isso excited about these films about vampires. It doesn’t make sense.</p><p>A: Of course it does. It’s like a modern tale of Romeo and Juliet. You have a couple that is in love but can’t be together because they are so different. Add in the fact that immortality and super human strengthis really sexy and there you have it! Plus the cast is hip, young people that make the movie even more enticing.</p><p>B: I don’t buy into that. I think it’s just a fad. Pretty soon this will pass and everyone will be into werewolves or zombies!</p><h3 id="_302-global-view-phobias" tabindex="-1"><a class="header-anchor" href="#_302-global-view-phobias"><span>[302] Global View - Phobias</span></a></h3><p>A: Are you excited about your trip next month?</p><p>B: Yes and no. I can’t wait to go to Europe, but at the same time I am terrified.</p><p>A: Why?</p><p>B: Well, I have aerophobia. I have a chronic fear of flying.</p><p>A: Oh really? I have an uncle who is also terrified of flying. It’s not that bad though, I mean, it is pretty scary to be in this big machine flying through the air at seven hundred miles per hour. I actually have arachnophobia.</p><p>B: You’re scared of spiders? I actually have two more phobias. Acrophobia and glossophobia.</p><p>A: I guess that explains why you are afraid of flying, but public speaking is not that bad.</p><p>B: Are you kidding? When I get on stage, my palms start to sweat, I get really nervous and I can hardly speak.</p><p>A: Well, I must confess I am a bit claustrophobic. I hate being in an elevator for more than 5 seconds.</p><p>B: We are such weirdos right?</p><h3 id="_303-daily-life-mexican-food" tabindex="-1"><a class="header-anchor" href="#_303-daily-life-mexican-food"><span>[303] Daily Life - Mexican Food</span></a></h3><p>A: Hello sir, welcome to Pistolera restaurant. May I take your order?</p><p>B: Yes, I would like the chicken cheese enchiladas with a side of guacamole.</p><p>A: I’m sorry sir, but we ran out of chicken. May I suggest our delicious beef burritos or cheese quesadillas? Both include a side of guacamole and jalapenos.</p><p>B: Sure I’ll have the burrito.. Do you have nachos?</p><p>A: Of course sir. Our nachos come with melted cheese and chili.</p><p>B: Sounds good.</p><p>A: Would you like anything to drink?</p><p>B: Sure, I’ll have a Corona.</p><h3 id="_304-daily-life-neat-freak" tabindex="-1"><a class="header-anchor" href="#_304-daily-life-neat-freak"><span>[304] Daily Life - Neat Freak</span></a></h3><p>A: Ugg, this bathroom is a pigsty!</p><p>B: Helen, why do you keep flushing the toilet? What’s wrong?</p><p>A: I just can’t stand it. It’s really gross in here! There’s a stain on the toilet seat, and the floor was wet and slippery. So I cleaned it!</p><p>B: You did what? Helen, I know it’s gross, but I’ve seen many public washrooms that are much worse. Why are you cleaning the counter top? are you out of your mind?</p><p>A: I can’t help myself; it’s just so disgusting in here!</p><p>B: Helen, this is not like your own bathroom. Just leave it to the cleaners,okay?</p><p>A: Hang on. I’m just gonna quickly wipe the sink and sweep the floor.</p><p>B: You’re such a neat freak! I’m outta here!</p><h3 id="_305-the-weekend-bowling" tabindex="-1"><a class="header-anchor" href="#_305-the-weekend-bowling"><span>[305] The Weekend - Bowling</span></a></h3><p>A: Alright, so the first thing that you need to know about bowling is that you should never cross that line where the lane begins.</p><p>B: Why not?</p><p>A: Because they polish and oil it to make the ball slide down. If you step there you will slip and fall.</p><p>A: OK, so I got my bowling shoes, my ball, our names on the scorecard, so now, how the heck do I play this?</p><p>A: You throw the ball down the lane and try to knock down all the pins. If you do, that is called a strike. If you don’t knock them all down on the first try, then you get a chance to get the spare. After ten frames, we add up the points and see who has the most. Three hundred is a perfect score, but very hard to get.</p><p>B: Got it! OK, I’m gonna give it a go. Oh no! My ball went in the gutter!</p><p>A: I told you, its harder than you think. Now let a pro show you how it’s done.</p><h3 id="_306-the-weekend-pick-up-lines" tabindex="-1"><a class="header-anchor" href="#_306-the-weekend-pick-up-lines"><span>[306] The Weekend - Pick Up Lines</span></a></h3><p>A: Let’s got out tomorrow night. We can go to a bar and try to find you a girlfriend.</p><p>B: I don’t think that’s a good idea. I am just not good with approaching someone and starting up a conversation.</p><p>A: Maybe you just need a few pick up lines,you know, break the ice.</p><p>B: Pick up lines don’t work!</p><p>A: Come on! You can just walk up to a girl and say: “If you were a booger I’d pick you first.”</p><p>B: What? Come on! That’s just lame! No girl would fall for that!</p><p>A: Fine, then you can say: “So there you are! I’ve been looking all over for YOU, the woman of my dreams!”</p><p>B: That’s a good one! I think that’s pretty funny.</p><p>A: Yeah, so you make her laugh, you make a fool of yourself a little bit and then you buy her a drink.</p><p>B: Ok, how does this sound: “I was so enchanted by your beauty that I ran into that wall over there. So I am going to need your name and number for insurance purposes.”</p><p>A: Nice! Let’s go!</p><h3 id="_307-the-office-small-talk-series-showing-interest" tabindex="-1"><a class="header-anchor" href="#_307-the-office-small-talk-series-showing-interest"><span>[307] The Office - Small Talk Series - Showing Interest</span></a></h3><p>A: Hey Michelle, this is my friend James. He&#39;s visiting Shanghai from New York.</p><p>B: Oh, hi James. Nice to meet you. So, uh. you visiting for business or pleasure?</p><p>C: Well, actually a little of both. I&#39;m meeting some business contacts but I&#39;m also taking some Mandarin classes too.</p><p>B: That&#39;s cool! How&#39;s it going?</p><p>C: Well, I&#39;m finding the classes pretty tough actually, but I&#39;m having a great time in Shanghai. It&#39;s really an amazing city.</p><p>B: It sure is. Are you staying for long?</p><p>C: Only two weeks unfortunately. I wish I could stay longer but.</p><p>B: Well listen, if you need someone to show youthe sights then just call me. I&#39;m having a little get together at my new apartment next week so if you want to drop bythen.</p><p>C: That sounds great. I&#39;d love to! Let me take down your number Michelle.</p><h3 id="_308-daily-life-boxers-and-briefs" tabindex="-1"><a class="header-anchor" href="#_308-daily-life-boxers-and-briefs"><span>[308] Daily Life - Boxers and Briefs</span></a></h3><p>A: Lily, I found a pair of men’s boxers in the laundry machine this morning!</p><p>B: What?! That’s weird. Are they your boyfriend’s?</p><p>A: Nah, Kevin only wears briefs. Plus, this pair is extra small!</p><p>B: What do they look like?</p><p>A: They’re light blue with thin pink stripes... Oh, and there’s a Snoopy on it which is hilarious, hahah...</p><p>B: Those are my undies!</p><h3 id="_309-global-view-indian-food" tabindex="-1"><a class="header-anchor" href="#_309-global-view-indian-food"><span>[309] Global View - Indian Food</span></a></h3><p>A: So where is this mystery restaurant that we are going to?</p><p>B: It’s an Indian restaurant! I know you have never had Indian food, so I thought you might want to try.</p><p>A: That sounds great! I am craving some type of beef dish.</p><p>B: Well, Indian cuisine actually doesn’t serve beef. You see, cows are a sacred animal, a very important element inthe Hindu religion, so beef is not eaten.</p><p>A: I see, so what are we having? Chicken?</p><p>B: There are many amazing dishes to choose from. We can havesome chicken tikka masalawhich is an amazing curry. It’s a bit spicy, but I think you can handle it.</p><p>A: Sounds good! I have always heard that Indian spices give a rich flavor to food.</p><p>B: Yeah. Also, we can have some Naan bread which is baked in a tandoori oven. Since you don’t use any utensils to eat, you can use this bread to scoop upthe curry or rice.</p><p>A: What about veggies?</p><p>B: They have a good variety of vegetable based dishes like palak paneer, vegetable samosas or Daal.</p><p>A: It all sounds exquisite! I can’t wait!</p><h3 id="_310-the-office-small-talk-2" tabindex="-1"><a class="header-anchor" href="#_310-the-office-small-talk-2"><span>[310] The Office - Small Talk 2</span></a></h3><p>A: So Michelle, let me introduce you to Maria. She&#39;s my colleague from Brazil. Maria, this is Michelle.</p><p>B: Hi Michelle. So what do you do here in Shanghai? I mean, what work do you do?</p><p>C: I work in advertising right now. How about you?</p><p>B: I&#39;m actually inthe wine business.</p><p>C: That sounds really great. I love wine myself! Is this your first time to Shanghai Maria?</p><p>B: No actually, I often visit. I usually come to China for business at least once a year. Also, I love the restaurants in Shanghai, so that&#39;s a good reason to come.</p><p>C: Me too. Actually, there&#39;s a great Brazilian restaurant I recommend. I mean, the food is delicious butthe service isn&#39;t so good. I often like to get together with friends and have a great barbecue there.</p><p>A: We should go together some time.</p><p>C: Wonderful idea! I&#39;d love that!</p><h2 id="p311-320" tabindex="-1"><a class="header-anchor" href="#p311-320"><span>P311-320</span></a></h2><h3 id="_311-the-office-sorry-i-m-late" tabindex="-1"><a class="header-anchor" href="#_311-the-office-sorry-i-m-late"><span>[311] The Office - Sorry I’m Late</span></a></h3><p>A: Okay everyone, shall we begin?</p><p>B: Sorry Maggie, but we are missing a few people. Can we hang on a sec?</p><p>A: Well, I did say eleven o’clock sharp, and it’s now five past so….</p><p>C: Hi everyone, I’m so sorry I’m late. It’s raining cats and dogs outside and I had to wait ages for a taxi.</p><p>A: Okay James, take a seat quickly please. Right, the subject ofthe meeting is.</p><p>D:Hi guys. Please excuse me ,I was held up in traffic.</p><p>A: Right, as I was saying the subject ofthe m…</p><p>E: Hi Maggie. I’m terribly sorry. The traffic is murder out there.</p><p>A: Sit down Bruno! Okay now, as you are aware, the topic for this meeting is ‘The importance of being punctual’. Who would like to start?</p><h3 id="_312-the-weekend-ordering-drinks" tabindex="-1"><a class="header-anchor" href="#_312-the-weekend-ordering-drinks"><span>[312] The Weekend - Ordering Drinks</span></a></h3><p>A: What Can I get you?</p><p>B: I’ll have a Cosmo please.</p><p>C: Dude! You can’t order a Cosmo! That’s a ladies drink, you’re embarrasing me!</p><p>B: What are you talking about? It’s a good drink!</p><p>C: It’s too soft! Order something with a little more kick to it!</p><p>B: Fine! I’ll have a sex on the beach.</p><p>C: You have to be kidding me!</p><p>B: Come on! It’s delicious! Especially when served in a pineapple or coconut.</p><p>C: Forget it, I’m ordering for you. I’ll have a Scotch on the rocks and my friend here will have a Manhattan. Put it on my tab. Here now this is a real drink!</p><p>B: That’s strong! This is going to get me wasted!</p><p>C: That’s the idea!</p><h3 id="_313-the-office-small-talk-3" tabindex="-1"><a class="header-anchor" href="#_313-the-office-small-talk-3"><span>[313] The Office - Small talk 3</span></a></h3><p>A: Hey Michelle! Is that you?</p><p>B: Wow, Grace! Long time no see! Where have you been?</p><p>A: Oh yeah. Well you see I got a promotion, so I moved tothe new Pudong office last September.</p><p>B: You did? Congratulations!</p><p>A: Thanks a lot. So how are things with you Michelle?</p><p>B: Well, same old same oldyou know. Nothing much has changed here.</p><p>A: Are you still seeing Chris?</p><p>B: No, actually we split up last month.</p><p>A: Oh dear. I&#39;m sorry to hear that.</p><p>B: But I met a really cute guy last night at a networking party so, ….....well, let&#39;s just wait and see......</p><p>A: Good for you Michelle!</p><h3 id="_314-daily-life-making-a-collect-call" tabindex="-1"><a class="header-anchor" href="#_314-daily-life-making-a-collect-call"><span>[314] Daily Life - Making A Collect Call</span></a></h3><p>A: This isthe operator, how may I help you?</p><p>B: Yes, I would like to make a collect call.</p><p>A: Ok sir, please dial the number. Now please state your name.</p><p>B: Tommy.</p><p>A: Please wait a moment. Hello, you have a collect call from Tommy. Would you like to accept the charges?</p><p>C: Yes of course.</p><p>A: Dad?</p><p>C: Yeah Tommy, what happened are you ok?</p><p>A: Yeah dad everything is ok. I’m calling you because I want to know if it’s ok for me to go to my friend’s house today after school.</p><p>C: Yeah sure no problem. You scared me to death! I’ve told you to make a collect call in case of an emergency only! Why didn’t you call me from your mobile phone?</p><p>B: I ran out of credit and I also didn’t have twenty five cents N forthe payphone. Sorry dad.</p><h3 id="_315-the-office-sending-a-quote-via-email" tabindex="-1"><a class="header-anchor" href="#_315-the-office-sending-a-quote-via-email"><span>[315] The Office - Sending A Quote Via Email</span></a></h3><p>A: Melanie, can you help me with something? We need to finalize the account with the Mexican Embassy and, I need some advice on phrasing this letter correctly in English.</p><p>B: Sure Tracy, let me just get my laptop. all set.</p><p>A: Okay, so……. toWhom It May Concern, I am writing.</p><p>B: Um, Tracy? I think that’s a little too formal. I know you want to be polite but you’ve already made contact with them, so in English you can be more relaxed inthe opening….</p><p>A: Okay, more relaxed. Got it…. Hey Sally, what’s up? It’s Tracy here, just.</p><p>B: Okay Tracy, now it’s too relaxed! You’ve still got to show some respect. How about starting with “Dear Ms. Cooper, I’m writing to confirm…?</p><p>A: Great, okay. “Dear Miss Cooper, I’m writing to confirm the final quotation forthe full page back cover color advertisement you requested forthe spring issue of Voila magazine.</p><p>B: That’s great….</p><p>A: “ The final costing, including advert design and production, comes to forty-five thousand six hundred RMB. We want payment ten working days before publication or we will cancel the ad. Thanks for…”</p><p>B: Woo, okay back up a second Tracy. That’s too direct. Can I suggest you say, &quot; please note thatfinal payment is due two working weeks before publication? You don’t want to offend her.</p><p>A: Oops okay. You are right. Then I can just end with “All the best, Tracy”</p><p>B: Hmmmm, maybe, but I’d play it safeand just finish with “Yours Sincerely”. That’s more professional.</p><p>A: Oh, Melanie you are a life saver, thank you!</p><h3 id="_316-daily-life-small-talk-series-4-discussing-recent" tabindex="-1"><a class="header-anchor" href="#_316-daily-life-small-talk-series-4-discussing-recent"><span>[316] Daily Life - Small Talk Series 4 - Discussing Recent</span></a></h3><p>A: Hi Michelle. Do you need to usethe photocopier?</p><p>B: Oh hi Jeremy. No please, go ahead. So how are you Jeremy? I was talking to Linda about you only last week.</p><p>A: Oh I&#39;m fine thanks. I&#39;m super busy with work actually. Did you hear about the Lawson contract?</p><p>B: No, tell me more.</p><p>A: Well, I was discussing the contract with Bill and he said that they metthe head of Lawsons last week.</p><p>B: And.</p><p>A: And hopefully they are going to confirm the deal on Wednesday, fingers crossed</p><p>B: That&#39;s great news Jeremy. Congratulations! Anyway, I must get back, but give my regards to your wife Monica.</p><p>A: I will Michelle. Speak to you soon.</p><h3 id="_317-the-office-first-paycheck" tabindex="-1"><a class="header-anchor" href="#_317-the-office-first-paycheck"><span>[317] The Office - First Paycheck</span></a></h3><p>A: Hey, Susan. Have you got a sec? I have some questions about my paycheck.</p><p>B: You bet, Emily. Pull up a chair.</p><p>A: Well, this is my first paycheck here inthe States and there are a few things I don’t understand. First off, what is this FICA, and SUI Y tax, and why are there deductions both for Medicare and for my health insurance plan?</p><p>B: OK, let’s start from the top of your pay stub. This number here represents your gross pay.</p><p>A: Yes, that’s easy enough to understand.</p><p>B: Then here we have a series of deductions. First off are the federal ones. FICA stands for Federal Insurance Contribution Act, or something like that. It’s your federal income tax. And then there’s Social Security and Medicare, which are both federal programs to help you out after you retire or if you were unable to work.</p><p>A: All right, I see. So the Medicare isn’t actually a health insurance I can use now.</p><p>B: That’s right. Below the federal deductions are the state deductions. There’s the state income tax, and then this SUI SDItax you were asking about is paying into an unemployment and disability fund that our state has set up, but you can see it’s a pretty small quantity that they take.</p><p>A: Yeah, I don’t mind giving them a dollar fifty for that. So there are two separate income taxes – one at a state level and one at a federal level?</p><p>B: That’s right. Not all states have an income tax. Some use higher property taxes or sales taxes instead.</p><p>A: I see. All right, well I think everything else I can figure out on my own. The deductions for health insurance and my 401(K) are pretty self-explanatory. Thanks for your help, Susan.</p><p>B: No problem! All those deductions do add up, and nobody’s net pay is as high as they’d like. I can understand why you’d want some explanation.</p><p>A: Yeah, I guess it’s the same in the UK, I just never paid much attention. See you later!</p><h3 id="_318-global-view-allergies" tabindex="-1"><a class="header-anchor" href="#_318-global-view-allergies"><span>[318] Global View - Allergies</span></a></h3><p>A: Argh...I feel terrible, I keep sneezing and my eyes are all watery, what’s wrong with me?</p><p>B: Wow, you’re not dying are you, it looks like you have a cold, you should take some medicine.</p><p>A: I don’t think it’s a cold, I feel fine if I move a few feet away from my desk.</p><p>B: Maybe we should put you into quarantine ha ha, jokes aside, I think you might have an allergy.</p><p>A: An allergy? I never thought about that, I don’t think I’m allergic to pollen though and I’m desensitized to bee stings after being stung so many times, Hmm…</p><p>A: Ow! Why did you chuck that peanut at me?</p><p>B: Just checking if you’re allergic to peanuts, I guess not.</p><p>A: Not funny! I could have gone into Anaphylactic Shock.</p><p>B: Okay my bad, how about dust? This office is full of it.</p><p>A: Yes the whole is office is dusty yet I only feel affected near our desks!</p><p>Cat: Meow meow meow</p><p>A: You brought your cat into the office?!</p><p>B: Yes, it’s Mr Snuffle’s birthday today, I didn’t want him to be alone on his special day!</p><p>A: ACHOO! Argh put it away ACHOO!</p><p>B: I guess we found the problem, your allergic to cats!</p><h3 id="_319-daily-life-small-talk-5-brief-talk-with-a" tabindex="-1"><a class="header-anchor" href="#_319-daily-life-small-talk-5-brief-talk-with-a"><span>[319] Daily Life - Small Talk 5 - Brief Talk With A</span></a></h3><p>B: A: Oh dear Miss, you are soaked! Wow, it&#39;s really raining heavily outside.</p><p>B: Yes, it sure is. I had to run here from work! I need to rush as I&#39;m on my lunch break.</p><p>A: Well please, why don&#39;t you go ahead of me in line? I&#39;m in no hurry.</p><p>B: Oh, that&#39;s so nice of you! Thank you very much.</p><p>A: My pleasure Miss. Actually, could you recommend what to eat here? I&#39;ve never been here before.</p><p>B: Sure. Well, the avocado sandwich is delicious, and it&#39;s the healthiest thing on the menu. Personally, I think the beef salad is the tastiest choice. I usually get that. Also, the milkshakes are the best milkshakes in town!</p><p>A: Well, thanks for the suggestions.</p><p>B: Oh, don&#39;t mention it.</p><h3 id="_320-global-view-taking-the-gmat" tabindex="-1"><a class="header-anchor" href="#_320-global-view-taking-the-gmat"><span>[320] Global View - Taking The GMAT</span></a></h3><p>A: I can’t seem to progress up the career ladder no matter how hard I try and I have been here for 2 years already!</p><p>B: Well, have you thought of getting an MBA? I heard it does wonders in getting you to the top.</p><p>A: An MBA hey… well my degree wasn’t in business, the business schools won’t be interested in me.</p><p>B: Nonsense! The business schools measure your ability through a test called GMAT.</p><p>A: GMAT? What does that stand for and what will the test contain?</p><p>B: Graduate Management Admission Test, it contains three parts; Analytical Writing Assessment, the Quantitative section, and the Verbal section. Not only does the test mark you on the number of questions answered but also on the difficulty.</p><p>A: Okay this sounds a little tough, how am I supposed to practice for this?</p><p>B: Up to you, you could have a one on one session with a tutor or group sessions, you can also use free or private computer software. Going to church might help as well!</p><p>A: No matter what I do I’m going to ace this test and go on to become a corporate fat cat!</p><p>B: Umm…That’s the spirit!</p><h2 id="p321-330" tabindex="-1"><a class="header-anchor" href="#p321-330"><span>P321-330</span></a></h2><h3 id="_321-global-view-thai-food" tabindex="-1"><a class="header-anchor" href="#_321-global-view-thai-food"><span>[321] Global View - Thai Food</span></a></h3><p>A: What did you cook?</p><p>B: Well, as you know I was in Thailand last month, and I took a cooking class! So I prepared some of my favorite dishes.</p><p>A: Great idea! As long as I don’t get food poisoning! So what is onthe menu tonight?</p><p>B: Ok, for starters we have Tom Yam soup. It’s a bit spicy, but really good!</p><p>A: This is delicious! The ginger and lemongrass really gives it a nice taste!</p><p>B: Now this next dish is one of the most famous. Foreigners call it papaya salad butthe proper name is Tom Sam. It is a spicy salad made from a mix of fresh vegetables including shredded unripened papaya and tomato.</p><p>A: This is delicious! The combination of sour and spicy is really interesting! I could have this everyday!</p><p>B: Ok, now forthe last and best dish in my opinion. This is called Pad Thai. It’s stir-fried noodles with eggs, fish sauce, tamarind juice, red chili pepper plus bean sprouts, shrimp and tofu and garnished with crushed peanuts and coriander. It’s practically Thailand’s national dish!</p><p>A: Wow, this is great! I never knew Thai food was so creative and delicious!</p><p>B: Wantsome more?</p><p>A: I’m stuffed!</p><h3 id="_322-the-office-small-talk-6-talking-about-yourself" tabindex="-1"><a class="header-anchor" href="#_322-the-office-small-talk-6-talking-about-yourself"><span>[322] The Office - Small Talk 6 - Talking About Yourself</span></a></h3><p>A: Excuse me, is this seat taken?</p><p>B: No, please feel free.</p><p>A: Thanks a lot.</p><p>B: Do you work in Shanghai?</p><p>A: Yes I do. How about you?</p><p>B: No, I&#39;m a tourist. This place is amazing! It&#39;s much bigger than I imagined, and much more exciting! There&#39;s so much to see here.</p><p>A: You can say that again! It&#39;s much more modern than people imagine. Where are you from?</p><p>B: Um, well let&#39;s see.....I&#39;m from Kansas originally. A much quieter and more peaceful place than here, that&#39;s for sure!</p><p>A: Uh huh....</p><p>B: But I&#39;m living in Paris right now.</p><p>A: Oh Paris! Wonderful, I&#39;d love to visit some time!</p><h3 id="_323-daily-life-cancelled-flight" tabindex="-1"><a class="header-anchor" href="#_323-daily-life-cancelled-flight"><span>[323] Daily Life - Cancelled Flight</span></a></h3><p>A: Good afternoon Sir, may I please see your passport and reservation?</p><p>B: Here you go.</p><p>A: I’m sorry sir, this flight has been cancelled due to some mechanical problems.</p><p>B: Cancelled! So what am I supposed to do now?</p><p>A: We apologize for any inconveniences that may be caused by this. If your flight is urgent, I can put you on a waiting list for another flight this evening, but it’s on a first come first served basis, so there is no guarantee that you will be able to take that flight.</p><p>B: What’s my other option?</p><p>A: If you can wait until tomorrow, we will put youup in a hotel for today and you can take scheduled flight for tomorrow morning.</p><p>B: That’s fine. I’ll do that then.</p><p>A: Thank you for your understanding sir. I will book your flight now.</p><h3 id="_324-global-view-thanksgiving-dinner" tabindex="-1"><a class="header-anchor" href="#_324-global-view-thanksgiving-dinner"><span>[324] Global View - Thanksgiving Dinner</span></a></h3><p>A: So what are you doing for Thanksgiving?</p><p>B: Not much really. It’s more of an American tradition, so back home we don’t really celebrate it. In fact, I am not even sure of what exactly is being celebrated!</p><p>A: Well you know, it’s a time to get together with all your family and be thankful for everything!</p><p>B: Yeah but, how did this holiday come to be?</p><p>A: Well, the first settlers of Massachusetts arrived there because of religious persecution from England and King James. Once inthe New World, they befriended an native named Squanto, who taught them how to harvest food from the area such as corn.</p><p>B: Interesting! I am amazed how big and delicious thanksgiving dinners are!</p><p>A: Come to my house for Thanksgiving! We are having turkey, pumpkin pie, mashed potatoes with gravy, and lots of stuffing!</p><p>B: Count me in!</p><h3 id="_325-the-office-small-talk-7-talking-about-a-trip" tabindex="-1"><a class="header-anchor" href="#_325-the-office-small-talk-7-talking-about-a-trip"><span>[325] The Office - Small Talk 7 - Talking About A Trip</span></a></h3><p>A: Hey Michelle. Good to see you. Are you at lunch?</p><p>B: Oh hi Jim. No I just got back. I thought you were on vacation now.</p><p>A: No, I wish I was! I just got back from Spain actually.</p><p>B: Oh wonderful! Have you been there before or was it your first time?</p><p>A: My first time. I&#39;ve traveled around Europe a lot, but this was my first time to Spain. It was amazing, and the weather was just beautiful! No rain, and just sun, sun, sun....</p><p>B: I&#39;m so jealous of you. I&#39;ve never been anywhere in Europe. I&#39;ve always dreamed of traveling around and seeing the sights.</p><p>A: Well, I really recommend Spain. You really should go.Anyway, it&#39;s been great to catch up, but I must be going, this is my floor. Speak again soon I hope.</p><p>B: For sure. Take care.</p><h3 id="_326-daily-life-report-card" tabindex="-1"><a class="header-anchor" href="#_326-daily-life-report-card"><span>[326] Daily Life - Report Card</span></a></h3><p>A: Look, Jimmy’s report came today.</p><p>B: Let’s have a look. What is this? Where are all the grades?</p><p>A: He’s in the third grade Sam! You see under each subject that he is being taught in school, he receives a mark from one to three. A one means his achievement or work is excellent. Here in Science for example he got a two, which means its satisfactory.</p><p>B: What about here in physical education?</p><p>A: He got a three here which means it’s unsatisfactory. We should work on that with him.</p><p>B: So confusing! In my day we got an A or B if we were doing well and if we failed an exam we would get an F!</p><h3 id="_327-daily-life-buying-a-pair-of-jeans" tabindex="-1"><a class="header-anchor" href="#_327-daily-life-buying-a-pair-of-jeans"><span>[327] Daily Life - Buying A Pair Of Jeans</span></a></h3><p>A: Excuse me, can I try on this pair of jeans?</p><p>B: Sure. Let me see... I’m afraid we don’t have any size eights left.</p><p>A: What are you talking about? I’m always a size four. Here, I’ll try these.</p><p>B: They seem a bit too tight. Shall I find you a larger size?</p><p>A: No, they fit fine! They show off my curves perfectly!</p><p>B: Yeah, your love handles. Yeah, they sure do, although... here, you forgot to close this button.</p><p>A: Yeah right, I’ll do it now...</p><h3 id="_328-the-office-small-talk-8-talking-about-work" tabindex="-1"><a class="header-anchor" href="#_328-the-office-small-talk-8-talking-about-work"><span>[328] The Office - Small Talk 8 - Talking About Work</span></a></h3><p>A: Ah Michelle hi. I was hoping to see you. How have you been? How&#39;s the family?</p><p>B: Oh hello Mr. Campbell. I&#39;m fine and Jack&#39;s doing well. How are you?</p><p>A: I&#39;m fine thanks. I got your report this morning. Thank&#39;s for that. Are you joining the conference today?</p><p>B: Yes, I&#39;m leaving at four pm. Mr Campbell Good, well we can discuss this more then, but I think the figures are looking very good for this quarter.</p><p>B: Yes, me too. Mr Campbell I&#39;m planning to discuss the advertising budget at the conference. I don&#39;t think we should continue with the TV advertising.</p><p>B: No, me neither. It&#39;s far too expensive.</p><p>A: Well, let&#39;s discuss this more at the conference. Maybe we can share a taxi there.</p><p>B: Yes, sure.</p><h3 id="_329-daily-life-going-to-the-bakery" tabindex="-1"><a class="header-anchor" href="#_329-daily-life-going-to-the-bakery"><span>[329] Daily Life - Going To The Bakery</span></a></h3><p>A: Welcome to Al’s Bakery. What can I get you?</p><p>B: Hi! Let me get a dozen croissants, four blueberry muffins and a loaf of sourdough bread. A:: Sure. Would you like to have the loaf sliced?</p><p>B: No, that’s OK. Do you have any whole wheat bread?</p><p>A: We are out at the moment. May I suggest some rye bread?</p><p>B: Sure that sounds good. Do you have any cakes?</p><p>A: We have various birthday cakes and also ice cream cakes.</p><p>B: I’ll just take a cheesecake.</p><p>A: Will that be all?</p><p>B: Yes.</p><p>A: Your total is forty three dollars and twenty cents.</p><h3 id="_330-the-weekend-fortune-telling" tabindex="-1"><a class="header-anchor" href="#_330-the-weekend-fortune-telling"><span>[330] The Weekend - Fortune Telling</span></a></h3><p>A: Look at this newspaper article about this famous local medium. It says that she is really gifted and so popular now, that she is booked solid with appointments for the next twelve months!</p><p>B: You don’t really believe in all that hocus pocus mumbo jumbo do you?</p><p>A: Well I have had many friends that went to a psychic and got their palms read and most of the things the psychic told her came true!</p><p>B: Of course it does! They tell you general and obvious things like that you will be successful or have a big house. I think most of the times they are just scam artists.</p><p>A: Well historically it is a practice that many cultures share. Reading the tarot cards, in the east they would even read tea leaves! I even heard that there are people that make you smoke a cigar, and then read your ashes.</p><p>B: All superstitious nonsense! I would still like to go to one and see what he or she has to say, just for kicks.</p><p>A: Great! I’ll make an appointment!</p><h2 id="p331-340" tabindex="-1"><a class="header-anchor" href="#p331-340"><span>P331-340</span></a></h2><h3 id="_331-the-office-small-talk-9-talking-about-the-weather" tabindex="-1"><a class="header-anchor" href="#_331-the-office-small-talk-9-talking-about-the-weather"><span>[331] The Office - Small Talk 9 - Talking About The Weather</span></a></h3><p>A: Hey Michelle, jump in quick. It&#39;s pouring out there!</p><p>B: Oh hi Melissa. Are you going to the conference too? I was planning to pick up Mr. Campbell.</p><p>A: Yes, he told me. We need to pick him up at his hotel and then go to the conference.</p><p>B: Oh I see, okay. So I heard you got married. Congratulations!</p><p>A: Ah thank you! I&#39;m very excited. We were going to get married next year, but then we decided to get married on holiday instead. It was wonderful.</p><p>B: That sounds so romantic! Jack and I were hoping to get married in Europe next year, but we had to postpone our plans. We just don&#39;t have the money!</p><p>A: I know what you mean. I think Shanghai is getting more and more expensive, don&#39;t you?</p><p>B: I sure do. In my opinion it&#39;s actually becoming more expensive than back home.</p><p>A: Definitely. Oh there&#39;s Mr. Campbell. Driver can you stop here please?</p><h3 id="_332-daily-life-setting-up-your-voice-mail-message" tabindex="-1"><a class="header-anchor" href="#_332-daily-life-setting-up-your-voice-mail-message"><span>[332] Daily Life - Setting Up Your Voice mail Message</span></a></h3><p>A: Can you help me set up my voicemail message? I just got this service and I am not really sure what I am supposed to say.</p><p>B: Sure! You just basically gotta let the caller know who they called, and ask them for their contact information so you can call them back.</p><p>A: Ok, so can I say, “ This is Abby’s voicemail. I will call you later, so leave me your name and number”.</p><p>B: That’s more or less the idea, but try something that sounds more friendly.</p><p>A: Ok, so how about this, “ This is Abby and I am really happy you called! I promise I will give you a ring as soon as I can, so please leave me your name and number. Talk to you soon!”.</p><p>B: A little too friendly Abby. Just say this, “ Hi, you have reached Abby. I am unable to answer your call right now, but if you leave me your name and phone number, I will get back to you as soon as possible. Thanks”.</p><p>A: That’s perfect! Can you say that again and record it for me?</p><h3 id="_333-global-view-human-anatmoy" tabindex="-1"><a class="header-anchor" href="#_333-global-view-human-anatmoy"><span>[333] Global View - Human Anatmoy</span></a></h3><p>A: OK class, so today we are going to continue with our anatomy class, today we will review everything we have learned. Can anyone tell me what the first major organ is?</p><p>B: The brain!</p><p>A: That’s right the brain! It serves as a control center for the body, handling the processes of the central nervous system as well as cognition. Then what major organ is in our chest?</p><p>B: The heart!</p><p>A: Very good! It pumps blood throughout the body, using the circulatory system such as blood vessels and veins. Now let’s not forget that our lungs provide oxygen to our heart and body to keep us alive! Now what about the organs that help us digest food?</p><p>B: The stomach and intestines!</p><p>A: Very good! Let’s not forget that the stomach is the one that breaks down our food and our intestines process that food and then expel the waste. Are we forgetting anything?</p><p>B: Yeah! Our kidneys, liver and bladder!</p><p>A: Oh yes, you are right. Very important organs indeed.</p><p>B: So what do these organs do teacher?</p><p>A: Well, ummm, they...Time for a break! We can talk about it when you get back.</p><h3 id="_334-the-office-small-talk-10-general-talk" tabindex="-1"><a class="header-anchor" href="#_334-the-office-small-talk-10-general-talk"><span>[334] The Office - Small Talk 10 - General Talk</span></a></h3><p>A: Hi ladies. Thanks for picking me up. It&#39;s awful weather out there!</p><p>C: Absolutely. It&#39;s been raining for hours.</p><p>A: How are you Melissa? Are you okay?</p><p>B: I&#39;m great thanks, Mr. Campbell.</p><p>C: Do you have any business trips planned soon Mr. Campbell?</p><p>A: Of course. I&#39;m always travelling! I will leave for London next Monday, and then I&#39;ll fly to Boston from there. It&#39;s going to be a busy month. How about you Michelle? Any vacation plans?</p><p>C: Yes. Mike and I will travel to Beijing to see Mikes parents for Spring festival, and hopefully next year we will visit London. I hear it&#39;s a wonderful city.</p><p>A: I couldn&#39;t agree more. London is really fantastic. It&#39;s my favorite city. I&#39;m sure you&#39;ll have a great time.</p><h3 id="_335-the-weekend-going-to-the-playground" tabindex="-1"><a class="header-anchor" href="#_335-the-weekend-going-to-the-playground"><span>[335] The Weekend - Going To The Playground</span></a></h3><p>A: Hey honey! Where were you?</p><p>B: I decided to take Kenny to the park and get some fresh air.</p><p>A: How was it? Were there a lot of kids?</p><p>B: It wasn’t too crowded, but we had a great time! We got on the see-saw together, the went on a couple of different slides and then I tried to go with him in the jungle gym, but I didn’t fit.</p><p>A: Sounds like fun! When we go he always just likes to play in the sandbox.</p><p>B: Yeah, but today he was really hyper. He even got on the monkey bars and then he went on to go on the swings for a half hour. I’m exhausted!</p><p>A: You should go to the park more often since you don’t go to the gym anymore!</p><h3 id="_336-daily-life-christmas-traditions" tabindex="-1"><a class="header-anchor" href="#_336-daily-life-christmas-traditions"><span>[336] Daily Life - Christmas Traditions</span></a></h3><p>A: What are you doing awake?</p><p>B: I can’t sleep...</p><p>A: But it’s almost midnight!</p><p>B: Exactly. I’m too excited for Christmas morning. Also, I thought I heard Santa.</p><p>A: Really? How do you know it was Santa?</p><p>B: Well I heard that naughty boys and girls get coal in their stockings, so I thought I’d be nice and make Santa cookies. I even left out some milk. I heard someone in the kitchen eating the cookies, so I came downstairs!</p><p>A: Hmm... well I know that Santa won’t come down the chimney with you hiding behind the tree, spying on him!</p><p>B: Really?</p><p>A: Really! Let’s go back upstairs and get back to bed. That way, we can let Santa do his job. Then when you wake up, it will be Christmas already!</p><p>B: O-K...</p><p>A: Hey, honey! Is that you? Don’t eat all the cookies I want some, too!</p><h3 id="_337-global-view-the-night-before-christmas" tabindex="-1"><a class="header-anchor" href="#_337-global-view-the-night-before-christmas"><span>[337] Global View - The Night Before Christmas</span></a></h3><p>Twas the night before Christmas, when all through the house Not a creature was stirring, not even a mouse; The stockings were hung bythe chimney with care, In hopes that St. Nicholas soon would be there; The children were nestled all snug in their beds, And mama in her &#39;kerchief, and I in my cap, Had just settled down for a long winter&#39;s nap, When out onthe lawn there arose such a clatter, I sprang from the bed to see what wasthe matter. Away tothe window I flew like a flash, Tore open the shutters and threw up the sash. The moon onthe breast ofthe new-fallen snow Gave the lustre of mid-day to objects below, When, what to my wondering eyes should appear, But a miniature sleigh, and eight tiny reindeer, With a little old driver, so lively and quick, I knew in a moment it must be St. Nick. More rapid than eagles his coursers they came, And he whistled, and shouted, and called them by name; &quot; Now, Dasher! now, Dancer! now, Prancer and Vixen! On, Comet! on Cupid! on, Donder and Blitzen! Tothe top ofthe porch! to the top ofthe wall! Now dash away! dash away! dash away all! As dry leaves that before the wild hurricane fly, When they meet with an obstacle, mount tothe sky, So up to the house-top the coursers they flew, With the sleigh full of toys, and St. Nicholas too. And then, in a twinkling, I heard onthe roof The prancing and pawing of each little hoof. As I drew in my head, and was turning around, Down the chimney St. Nicholas came with a bound. He was dressed all in fur, from his head to his foot, And his clothes were all tarnished with ashes and soot; A bundle of toys he had flung on his back, And he looked like a peddler just opening his pack. His eyes -- how they twinkled! his dimples how merry! His cheeks were like roses, his nose like a cherry! His droll little mouth was drawn up like a bow, Andthe beard of his chin was as white asthe snow; The stump of a pipe he held tight in his teeth, Andthe smoke it encircled his head like a wreath; He had a broad face and a little round belly, That shook, when he laughed like a bowlful of jelly. He was chubby and plump, a right jolly old elf, And I laughed when I saw him, in spite of myself; A wink of his eye and a twist of his head, Soon gave me to know I had nothing to dread; He spoke not a word, but went straight to his work, And filled allthe thestockings; then turned with a jerk, And laying his finger aside of his nose, And giving a nod, upthe chimney he rose; He sprang to his sleigh, to his team gave a whistle, And away they all flew like the down of a thistle. But I heard him exclaim, ere he drove out of sight, &quot; Christmas to all, and to all a good-night.</p><h3 id="_338-daily-life-having-leftovers" tabindex="-1"><a class="header-anchor" href="#_338-daily-life-having-leftovers"><span>[338] Daily Life - Having Leftovers</span></a></h3><p>A: What’s for dinner?</p><p>B: Leftovers.</p><p>A: What? Leftovers of what and from when?</p><p>B: From last night! I took the left over turkey, mixed it with some diced peppers and onions, added a little bit of mayonnaise and made some sandwiches!</p><p>A: Isn’t that dangerous though? I mean bacteria and germs reproducing on food that was left out or reheated?</p><p>B: Well, I didn’t leave the turkey out at room temperature for more than a an hour and I refrigerated it soon after we finished eating. Also, when reheating, I put it inthe oven for fifteen minutes at one hundred degrees Celsius.</p><p>A: Well ok, I am just afraid of getting food poisoning.</p><p>B: Don’t worry about it! Making a new meal out of leftovers is almost an art! Not only do you save money, but you also get to be creative and have something different to eat!</p><h3 id="_339-global-view-parent-teacher-conference" tabindex="-1"><a class="header-anchor" href="#_339-global-view-parent-teacher-conference"><span>[339] Global View - Parent Teacher Conference</span></a></h3><p>A: Thank you for coming tonight Mrs. Webber. As a teacher, it’s great seeing the kid’s parents assist our parent-teacher conference night.</p><p>B: Of course! I am very interested to know how my child is doing and also get some insight from you as to how he can improve.</p><p>A: Well Allen is a great student. He is a hard worker and very well behaved, however he does struggle a bit with math.</p><p>B: I guess he gets that from me, I never did well in math when I was a kid. What can I do at home to compliment what he is learning in the classroom.</p><p>A: Well, it’s important that you sit with him and review his homework assignments and help him with math. I would also recommend he stay after school twice a week for tutoring sessions. It will really help a lot.</p><p>B: Thanks a lot! I will definitely do that. Is there anything else?</p><p>A: Um.. yes. Here is a notice from our financial department, seems your child’s tution is overdue.</p><p>B: Oh yes, I....</p><h3 id="_340-global-view-happy-new-year" tabindex="-1"><a class="header-anchor" href="#_340-global-view-happy-new-year"><span>[340] Global View - Happy New Year!</span></a></h3><p>B: I know it’s so exciting! A new year is always like a clean slate. A:: fresh start to accomplish any dreams, objectives and goals.</p><p>A: Do you have a New Year’s resolution?</p><p>B: I was thinking about it, but I’m never able to keep my New Year’s resolution. Last year for example I joined a gym and only went twice.</p><p>A: Yeah I know what you mean. That’s why this year I am keeping things more simple. Maybe like getting together with friends I haven’t seen in a long time, or doing some volunteering work.</p><p>B: That seems reasonable. We should get together and watch the ball drop in Times Square.</p><p>A: Sure, as long as you don’t try to kiss me at midnight!</p><p>B: Well, we can’t break tradition! It’s bad luck!</p><h2 id="p341-350" tabindex="-1"><a class="header-anchor" href="#p341-350"><span>P341-350</span></a></h2><h3 id="_341-daily-life-baking-a-cake" tabindex="-1"><a class="header-anchor" href="#_341-daily-life-baking-a-cake"><span>[341] Daily Life - Baking A Cake</span></a></h3><p>A: Ok, so are you ready to learn how to bake a cake?</p><p>B: Almost, let me just put my apron on.</p><p>A: Ok, so the first thing we are going to do is preheat the oven, that way we have it at the desired temperature once we finish preparing everything. Set it to three hundred and seventy five degrees Fahrenheit.</p><p>B: Got it.</p><p>A: No we are gonna make the batter. Take some butter and sugar and mix it lightly until you have a nice consistency. Then add some vanilla extract and eggs and continue mixing.</p><p>B: Do I have to use a whisk or can I use the electric mixer?</p><p>A: Go ahead and use the mixer, but put it on medium speed. I’m gonna sift the flour and baking powder separately and then we can mix it with milk and the rest of the ingredients.</p><p>B: Ok, so now we need a baking pan right?</p><p>A: Yeah, but grease and flour it first so the cake won’t stick to it when it bakes.</p><p>B: Done. So how long do we bake it for?</p><p>A: We can leave it in there for about twenty five minutes. Then we let it cool for ten minutes before we remove the cake from the pan.</p><p>B: Wow! This was a lot easier than I thought!</p><h3 id="_342-global-view-at-the-library" tabindex="-1"><a class="header-anchor" href="#_342-global-view-at-the-library"><span>[342] Global View - At The Library</span></a></h3><p>A: Wow! Look at all these books! I bet I can find a book about anything here!</p><p>B: Shhh!! Please keep your voice down. There are people reading and studying here.</p><p>A: Ok, I’m sorry. Are you the librarian? Maybe you can help me, I am looking for a book.</p><p>B: Yes I am. You can check our online catalog to search the book you want based on the genre, title or if you know the author, I can point you towards the right direction.</p><p>A: I am looking for a book that has nursery rhymes.</p><p>B: That would be in our children’s section. That book shelf there on the right.</p><p>A: Ok, I would like to check out these books.</p><p>B: Do you have a library card?</p><p>A: No. How do I get one?</p><p>B: I just need to see your drivers license or utility bill to prove that you a resident of this state.</p><p>A: Here you go.</p><p>B: So you are all set. You can have these books for two weeks. If you need to have them longer, you can bring them here to renew them. If you don’t, you get charged ten cents a day for each book.</p><p>A: Ok, thanks!</p><h3 id="_343-daily-life-seafood-dinner" tabindex="-1"><a class="header-anchor" href="#_343-daily-life-seafood-dinner"><span>[343] Daily Life - Seafood Dinner</span></a></h3><p>A: This is such a nice restaurant! I feel so classy!</p><p>B: Yeah, it’s a little bit pricey, but they serve the best seafood in town.</p><p>C: May I Take your order?</p><p>B: Yes, I would like some marinated grilled shrimp for starters and I’ll also have the lobster.</p><p>C: Excellent choice sir. And for you madame?</p><p>B: I would like the baked oysters and the seafood platter.</p><p>C: Very good madame.</p><p>B: That seafood platter sounds good. Excuse me, what does the platter have?</p><p>C: It’s a great combination of clams, scallops, squid mussels, calamari and fillets of salmon and tuna. It comes with a side of butter sauce and french fries.</p><p>B: That sounds great! Cancel the lobster and give me one of the same please.</p><p>C: Very well sir. Anything to drink?</p><p>A: Can we get a bottle of your house white wine please?</p><p>C: Superb choice. I will be back shortly with the wine.</p><h3 id="_344-global-view-booking-a-hotel-room" tabindex="-1"><a class="header-anchor" href="#_344-global-view-booking-a-hotel-room"><span>[344] Global View - Booking A Hotel Room</span></a></h3><p>A: Madison Suites, how may I help you?</p><p>B: Yes, I’m calling from Mexico. I will be in town next week and would like to know if you have availability.</p><p>B: OK ma’am, can you tell me the date you expect to check in?</p><p>A: Yes, July ninth. I will be there for seven nights.</p><p>B: We have a junior single suite or a superior double suite available for those dates.</p><p>A: What’s the difference?</p><p>B: The junior suite is smaller and has one twin bed, while the superior suite has a double bed and mini-bar.</p><p>A: OK, I would like to reserve the superior suite. Is breakfast included?</p><p>B: Yes, a buffet breakfast is served every morning. I will need your name and your credit card details in order to complete the reservation.</p><p>A: Sure, my credit card number is...</p><h3 id="_345-daily-life-working-out" tabindex="-1"><a class="header-anchor" href="#_345-daily-life-working-out"><span>[345] Daily Life - Working Out</span></a></h3><p>A: Do you want to go catch a movie tonight?</p><p>B: I can’t, I have to go tothe gym.</p><p>A: Come on! You can go tomorrow, just skip it today. It’s not as if you are gonna get in trouble!</p><p>B: Actually I will! I am working out with a personal trainer that gets on my case if I don’t go. I like it, because it makes me feel more obligated to go and get healthy.</p><p>A: That’s cool, does your personal trainer basically teach you how to work out?</p><p>B: Yeah. He makes a work put plan depending onthe areas I want to work on, orthe muscles I want to build. Like for example in order to get better muscle tone in my abs, pecs and biceps, he makes me work out with free weights. Then for my quads, calves and hamstrings, I do leg lifts or squats.</p><p>A: Sounds like you are really getting in shape!</p><h3 id="_346-global-view-all-about-wines" tabindex="-1"><a class="header-anchor" href="#_346-global-view-all-about-wines"><span>[346] Global View - All About Wines</span></a></h3><p>A: Hello there, welcome to Wine World. Let me know if I can help you out at all.</p><p>B: Um, yes, please, I could really use some help. I’m going over to my boss’ house for dinner tonight and don’t know what kind of wine I should bring.</p><p>A: OK, do you know what kind of food will be served?</p><p>B: Well, his wife is Japanese. He said she makes really good sushi.</p><p>A: Hmm, that’s a bit of a challenge. Sushi is notoriously difficult to pair with wine. Well, let’s see. have to be a white wine, of course.</p><p>B: Why? Wouldn’t a red wine go well with sushi?</p><p>A: No, I don’t think so. Sushi is a very delicately flavored food, and red wine would be a jarring contrast. You need a white wine, which has more subtle flavors, to complement the fish.</p><p>B: I see. So should I get a bottle of Chardonnay? That’s a white wine, right?</p><p>A: Yes, Chardonnay is a white wine, but I’m not sure it’d be your best bet. Chardonnay is one of the more full-bodied whites, and tends to be a bit oaky. I’d suggest that you go for something brighter, like this Sauvignon Blanc from New Zealand.</p><p>B: Sauvignon Blanc? What’s that?</p><p>A: That’s another varietal, or type of grape, just like Chardonnay.</p><p>B: Let’s see. The label says it’s got &quot;attractive citrus and grassy aromas that give way to crisp, mineral flavors and a bone-dry finish. Serve chilled.&quot; Oh, no, how long will it take to chill the wine? I’m on my way to the dinner now.</p><p>A: It’s OK, don’t worry, we’ll just choose a wine from the cooler. We don’t have quite as extensive a selection over here, but...this Rhone Valley white would be lovely.</p><p>B: All right. What varietal is that?</p><p>A: Well, this is a French wine, so they don’t always specify the varietal on the label. The French believe that the soil a grape is grown in is one of the most important factors in the final flavor of the wine. This wine is probably a blend of a few different types of grapes, mostly Viognier, I’d guess.</p><p>B: And you think this is a good wine?</p><p>A: Yes, this is one of our best-sellers. It’s not quite as dry as the Sauvignon Blanc we were looking at earlier, which means it’s more approachable. It’s light and crisp, with a bit of a vanilla aroma.</p><p>B: Perfect! I’ll take it!</p><h3 id="_347-global-view-immigration-and-customs" tabindex="-1"><a class="header-anchor" href="#_347-global-view-immigration-and-customs"><span>[347] Global View - Immigration and Customs</span></a></h3><p>A: Good afternoon, passport and arrival card please.</p><p>B: Here you are.</p><p>A: Where are you coming from?</p><p>B: China.</p><p>A: Is this your country of birth or residence.</p><p>B: I just work there.</p><p>A: What is the purpose of your visit to the United States?</p><p>B: I’m here on vacation.</p><p>A: How long do you plan to stay in the United States?</p><p>B: Almost three weeks.</p><p>A: Sir, you didn’t fill out the information on your arrival card of where you will be staying.</p><p>B: Oh, I’m sorry, but there are a couple of different places I will travel to within the United States, so I wasn’t sure what to put.</p><p>A: You must specify an address of the place where you will spend most of your time.</p><p>B: Ok, here you are.</p><p>A: Do you have enough means to support yourself while you are here?</p><p>B: Yes. I have some travellers cheques and two credit cards.</p><p>A: Very good. Do you have anything to declare?</p><p>B: Nope. I only have my clothes and camera!</p><p>A: Very well sir, welcome to the United States, enjoy your visit.</p><h3 id="_348-the-weekend-talking-about-skincare" tabindex="-1"><a class="header-anchor" href="#_348-the-weekend-talking-about-skincare"><span>[348] The Weekend - Talking About Skincare</span></a></h3><p>A: You want to go get a facial with me today?</p><p>B: Dude, what are you talking about? Only girls do that.</p><p>A: Not at all, guys also get facials, manicures and pedicures. There is nothing wrong with looking after your skin and looking good.</p><p>B: True. So what do they do to you at your beauty spa?</p><p>A: Well, first they exfoliate my face, getting rid of all the dead skin. Then I get a face mask with nutrients that keep my skin healthy and young. Afterwards, they apply some moisturizer and you leave feeling like a million bucks.</p><p>B: That doesn’t really sound like something I would be interested in. In any case, I just wash my face every night and use sunscreen during the day.</p><p>A: Well you should come with me one day, I’m sure you’ll love it.</p><p>B: Uh... no.</p><h3 id="_349-global-view-chinese-medicine" tabindex="-1"><a class="header-anchor" href="#_349-global-view-chinese-medicine"><span>[349] Global View - Chinese Medicine</span></a></h3><p>A: What’s wrong?</p><p>B: I have a headache. These past few days I’ve been living off painkillers. Man, I feel like my head is going to explode.</p><p>A: You should get acupuncture treatment. My mom was always having headache issues and it was acupuncture that cured her.</p><p>B: The results are too slow. On top of that, just the thought of smoking needles poking into my flesh frightens me.</p><p>A: They don’t just randomly stick you, they find your pressure points. The heat allows the body to immediately respond to the treatment, restoring the body’s ”chi”.</p><p>B: But I get scared the moment I see a needle. How could I stand having needles in my body for hours on end?</p><p>A: The needles are very thin, and as long as the doctor’s technique is good, and the patient himself is relaxed, it won’t hurt–on the contrary it will actually alleviate pain. Now there are high-tech needles that are micro thin; they don’t hurt at all. However, if you are really scared of acupuncture, scraping or cupping are also options.</p><p>B: Scraping is too terrifying. When they finish scrapping, your body is all red, as if you were just tortured. Cupping is the same, your body ends up with red circles all over it–looks like someone beat you up.</p><p>A: This only signifies that the toxins have left the body. Actually, there is only discomfort during the treatment process. Once it’s over you feel very comfortable.</p><p>B: Chinese medicine is strange. The patients are already ill, and then the doctor makes them suffer more.</p><p>A: This is the only way to get at the problem. Anyway, if you want to relieve the pain,You are just going to have to be tough and do it.</p><p>B: Forget it. I don’t want to inflict any more pain on myself. In a little while I’ll go and buy some more painkillers and take a nap.</p><h3 id="_350-daily-life-talking-about-relatives" tabindex="-1"><a class="header-anchor" href="#_350-daily-life-talking-about-relatives"><span>[350] Daily Life - Talking About Relatives</span></a></h3><p>A: What are you doing this weekend?</p><p>B: My brother in law is having a small get together at his house and he invited me.</p><p>A: Is it a family thing or just friends?</p><p>B: A bit of both. Some cousins, aunts and uncles will be there, but also some friends from the neighborhood.</p><p>A: Is your great uncle Rick going to be there? He is really funny.</p><p>B: Yeah he is going to be there with his step-son and his ex-wife.</p><p>A: You mean your sister?</p><p>B: No, Rick is actually my great uncle, so he is my grandmother’s brother.</p><p>A: You lost me.</p><p>B: I’ll explain later, let’s go.</p><h2 id="p351-360" tabindex="-1"><a class="header-anchor" href="#p351-360"><span>P351-360</span></a></h2><h3 id="_351-daily-life-vaccinations" tabindex="-1"><a class="header-anchor" href="#_351-daily-life-vaccinations"><span>[351] Daily Life - Vaccinations</span></a></h3><p>A: Hello Mrs Parker, how have you been?</p><p>B: Hello Dr Peters. Just fine thank you. Ricky and I are here for his vaccines.</p><p>A: Very well. Let’s see, according to his vaccination record, Ricky has received his Polio, Tetanus and Hepatitis B shots. He is 14 months old, so he is due for Hepatitis A, Chickenpox and Measles shots.</p><p>B: What about Rubella and Mumps?</p><p>A: Well, I can only give him these for now, and after a couple of weeks I can administer the rest.</p><p>B: Ok great. Doctor, I think I also may need a Tetanus booster. Last time I got it was maybe fifteen years ago!</p><p>A: We will check our records and I’ll have the nurse administer the booster as well. Now, please hold Ricky’s arm tight, this may sting a little.</p><h3 id="_352-global-view-the-7-wonders-of-the-world" tabindex="-1"><a class="header-anchor" href="#_352-global-view-the-7-wonders-of-the-world"><span>[352] Global View - The 7 Wonders Of The World</span></a></h3><p>A: Have you seen this news article? Apparently an organization has made a list to name the new seven wonders of the world and people could vote for them online.</p><p>B: Wow, that’s really interesting. So who won?</p><p>A: Well, the Great Wall of China, the Taj Mahal in India.</p><p>B: I’ve been there! It really is an amazing work of architecture and art. The entire complex is made of white marble and in the interior of the tomb, the walls are covered with gems and emeralds!</p><p>A: Cool! Also amongst the winners is Petra, in Jordan, Machu Picchu in Peru and the pyramid in Chichenitza in Mexico.</p><p>B: Wait a minute! It also says that the Christ Redeemer statue in Brazil and the Colosseum in Rome are wonders. I would love to go to Italy and see the Colosseum, stand in the middle like a gladiator!</p><p>A: Well, let’s see if we can find some cheap airfare and we can go towards the end of the year.</p><p>B: Good idea!</p><h3 id="_353-global-view-college-life" tabindex="-1"><a class="header-anchor" href="#_353-global-view-college-life"><span>[353] Global View - College Life</span></a></h3><p>A: Hey, Jordan, is that you? Long time no see!</p><p>B: Oh, hey, no kidding! I haven’t seen you since orientation three months ago! So how’ve you been? Settling into college life OK?</p><p>A: Yeah, I think so! I pledged Phi Iota Alpha, so I’m living atthe frat house now.</p><p>B: Oh, so you’re a frat boy now, huh?</p><p>A: Yeah, yeah, I know, it’s totally cliche´, but really, I think it’s been a good decision. I’ve got a lot of support and good suggestions from the guys. What about you? What have you been up to?</p><p>B: Not much. I’m still living at home and commuting to school. I ended up dropping that metalworking class I was so excited about. It just wasn’t as interesting as I’d hoped. The guidance counselor suggested that I focus on my prerequisite courses so that I can make sure the credits count.</p><p>A: That sounds smart...but kind of boring.</p><p>B: Yeah, it is, a little bit. I joined the Great Outdoors Club, though, which has been a lot of fun. We’ve gone on two camping trips already, and I’ve made some good friends.</p><p>A: That’s cool. Hey, so have you decided on your major yet?</p><p>B: Definitely pre-med. What about you?</p><p>A: I still have no clue...but we don’t have to declare a major ‘til our sophomore year, so I’ve got time! Oops, I’m late for class. Gotta run!</p><p>B: OK, take care! Hey, nice running into you!</p><p>A: Yeah, you too!</p><h3 id="_354-global-view-homeschooling" tabindex="-1"><a class="header-anchor" href="#_354-global-view-homeschooling"><span>[354] Global View - Homeschooling</span></a></h3><p>A: I think we should home school our children when we decide to have kids.</p><p>B: What? Why?</p><p>A: Well, our public schools here are not very good and private school are just too expensive. I have been reading up on home schooling and it has a lot of advantages.</p><p>B: Like what? I think that by doing something like that we would be isolating our children from social interaction.</p><p>A: Well, first of all, I would be able to teach them everything they learn in school in a more relaxed and fun way. I also think that having a one-on-one class is much better since you can focus more on his or her strengths or weaknesses.</p><p>B: I think neither your parents or mine would agree to such an idea.</p><p>A: I will bring it up over Sunday brunch.</p><p>B: Good luck with that!</p><h3 id="_355-daily-life-lending-money" tabindex="-1"><a class="header-anchor" href="#_355-daily-life-lending-money"><span>[355] Daily Life - Lending Money</span></a></h3><p>A: Can I borrow five bucks?</p><p>B: No!</p><p>A: Come on! I’ll pay you back on Tuesday.</p><p>B: Last time I lent you money, you never paid me back.</p><p>A: I promise if you lend me five dollars today, I will repay you in full next week.</p><p>B: Ok, but I’m taking your skateboard as collateral.</p><p>A: Fine! I can’t believe you don’t trust me.</p><p>B: It’s nothing personal, just business.</p><h3 id="_356-daily-life-coins-and-money" tabindex="-1"><a class="header-anchor" href="#_356-daily-life-coins-and-money"><span>[356] Daily Life - Coins and Money</span></a></h3><p>A: Help me organize these coins.</p><p>B: That’s a lot of money! What did you do? Break the piggy bank?</p><p>A: Yeah, I’m gonna go to the bank and change it for bills, but first I have to separate them into little piles.</p><p>B: Ok, I’ll find all the quarters and dimes while you sort the nickels and pennies.</p><p>A: Great, then we can add everything up and take it to the bank.</p><p>B: I found some coins that are not from here.</p><p>A: Oh yeah, those are from my trip to London. I have a couple of different pence, but in all it won’t add up to one pound.</p><p>B: Are you sure the bank will change these coins for you?</p><p>A: Hopefully!</p><h3 id="_357-daily-life-making-a-dinner-reservation" tabindex="-1"><a class="header-anchor" href="#_357-daily-life-making-a-dinner-reservation"><span>[357] Daily Life - Making A Dinner Reservation</span></a></h3><p>A: Bruno Bistro, how may I help you?</p><p>B: Yes hello, I would like to make a reservation please.</p><p>A: Certainly sir, For which day and time please?</p><p>B: Tonight at seven.</p><p>A: I’m sorry sir, but we are fully booked tonight until eight.</p><p>B: In that case, eight o’clock is fine.</p><p>A: Very well, and how many people will attend tonight?</p><p>B: Four people.</p><p>A: Lastly, may I please know what name I should make the reservation under?</p><p>A: Mark.</p><h3 id="_358-daily-life-text-me" tabindex="-1"><a class="header-anchor" href="#_358-daily-life-text-me"><span>[358] Daily Life - Text Me</span></a></h3><p>A: Why didn’t you text me last night?</p><p>B: What? I sent you three or four messages!</p><p>A: I didn’t get any of them. I was waiting for you to text me the address of where the party was and I never got your message.</p><p>B: Why didn’t you just call? I hate sending SMS messages.</p><p>A: Well, because I didn’t have any credit on my phone. I used it all up this month.</p><p>B: I thought you had an unlimited SMS plan?</p><p>A: I do, but if I don’t have any credit in my phone, it won’t let me call or send messages.</p><p>B: No wonder you didn’t get my texts!</p><h3 id="_359-global-view-e-mail-scam" tabindex="-1"><a class="header-anchor" href="#_359-global-view-e-mail-scam"><span>[359] Global View - E-mail Scam</span></a></h3><p>A: I got an urgent email from Tom! He says he is in London and got robbed and needs us to wire him some money for his hotel.</p><p>B: What? That sounds really dodgy tome.</p><p>A: No way, Tom is an honest person, he wouldn’t lie tome.</p><p>B: No I mean, it seems like someone may have hacked his email account and sent that out. I mean think about it, why would he email you instead of calling you.</p><p>A: Do you really think someone is trying to scam people into sending money?</p><p>B: For sure! There are so many con artists out there, you never really know.</p><h3 id="_360-global-view-urban-legends" tabindex="-1"><a class="header-anchor" href="#_360-global-view-urban-legends"><span>[360] Global View - Urban Legends</span></a></h3><p>A: Have you read all these crazy things that are going on around the world?</p><p>B: What do you mean?</p><p>A: I was reading about how some people get tricked or drugged in their hotel rooms and have their organs removed! Then they are sold onthe black market.</p><p>B: Don’t tell me you actually believe all that? Don’t beso gullible, they are just urban legends. They are just stories people make up to scare you.</p><p>A: Well, I was also reading about how some popular songs have subliminal or even satanic messages if you play them backwards! Can you believe that?</p><p>B: You really think an artist or songwriter is going to go through the trouble of putting subliminal or satanic messages in a song? Don’t beso naive!</p><p>A: Well maybe you are right, but how about the story of how KFC has rows of headless chickens which are super grown in order to get bigger chickens faster!</p><p>B: Sounds a bit too far fetched to be true don’t you think?</p><h2 id="p361-365" tabindex="-1"><a class="header-anchor" href="#p361-365"><span>P361-365</span></a></h2><h3 id="_361-daily-life-fast-food" tabindex="-1"><a class="header-anchor" href="#_361-daily-life-fast-food"><span>[361] Daily Life - Fast Food</span></a></h3><p>A: I’m hungry, let’s order up something to eat.</p><p>B: Ok, maybe we can order a soup and a salad from the restaurant down the street.</p><p>A: I was thinking of getting a hamburger, fries and a chocolate sundae.</p><p>B: You eat too much junk food. That sort of stuff clogs up your arteries and is very high in cholesterol.</p><p>A: Well I never seem to gain weight so I don’t mind.</p><p>B: It’s not only about getting fat or not, it’s about being healthy. You could really have some health problems later on.</p><p>A: How about pizza or maybe some fried chicken! Better yet, let’s order some hot dogs!</p><p>B: You are a lost cause.</p><h3 id="_362-daily-life-what-mood-are-you-in" tabindex="-1"><a class="header-anchor" href="#_362-daily-life-what-mood-are-you-in"><span>[362] Daily Life - What Mood Are You In?</span></a></h3><p>A: Are you ok? You seem a bit anxious.</p><p>B: Yeah I’m OK, I have been having a lot of mood swings lately. I think it has to do with the pills my doctor prescribed that are causing chaos on my hormones.</p><p>A: So you mean you feel ecstatic one minute and then blue the next?</p><p>B: Yeah, it’s weird. For example just this morning I was feeling detached and lonely, even though there was really no reason to feel that way.</p><p>A: Well, maybe your mood will swing positively and you will feel confident, brave and hopeful!</p><p>B: I hope you are right.</p><h3 id="_363-daily-life-living-with-your-parents" tabindex="-1"><a class="header-anchor" href="#_363-daily-life-living-with-your-parents"><span>[363] Daily Life - Living With Your Parents</span></a></h3><p>A: Why did your girlfriend break up with you?</p><p>B: I don’t know, she said she was tired of me not manning up and being more independent, which I think is all a bunch of crap.</p><p>A: Well, you still live with your parents, so she does have a point.</p><p>B: What do you mean? Lots of people live with their parents, especially when rent isso expensive andthe slump inthe economy.</p><p>A: Yeah, but you are almost forty! Plus, you make good money so there is really no excuse. It’s simply because you are a momma’s boy.</p><p>B: Whatever dude, I have everything I need, why would I move out! Have a great roof over my head, my mom does my laundry and cooks for me, what else could a guy ask for!</p><p>A: Let’s agree to disagree.</p><h3 id="_364-daily-life-hiring-help" tabindex="-1"><a class="header-anchor" href="#_364-daily-life-hiring-help"><span>[364] Daily Life - Hiring Help</span></a></h3><p>A: Can you help me write a newspaper ad?</p><p>B: Sure, what are you looking to buy or sell?</p><p>A: Actually, I want to hire someone to help me around the house.</p><p>B: Oh, you want to get a maid?</p><p>A: Well, I think it’s better if you call her a cleaning lady or domestic help.</p><p>B: Ok, so what do you wanther to do?</p><p>A: Well, let’s see. I wanther to come in three times a week for a couple of hours to clean the kitchen, bathroom and maybe do some cooking.</p><p>B: Got it. And how much do you offer per month?</p><p>A: I would pay her hourly, I don’t know what the going rate is though.</p><p>B: I know for sure it’s more than minimum wage but maybe you should just negotiate with the person that answers the ad.</p><p>A: Great! Thanks for your help!</p><h3 id="_365-daily-life-household-chores" tabindex="-1"><a class="header-anchor" href="#_365-daily-life-household-chores"><span>[365] Daily Life - Household Chores</span></a></h3><p>A: Kevin, what is this mess? It looks like a pigsty in here! Clean this up!</p><p>B: Ok dad, I will do it in a minute, let me just finish this level of this game.</p><p>A: No, I said now! Plus, you are grounded, you’re not allowed to play video games. I wantyou to make your bed, dothe laundry and then come downstairs and sweep the floors.</p><p>B: That’s so unfair!</p><p>A: You have to pull your weight around here young man. My house, my rules.</p><p>B: But I already mopped the floors, dusted the furniture and vacuumed the rugs!</p><p>A: That’s great, but you still have work to do, so get to it.</p>',675)])])}const l=a(n,[["render",s]]),p=JSON.parse(`{"path":"/English/EnglishPod/EnglishPod_301-365/","title":"EnglishPod_301-365","lang":"en-US","frontmatter":{"title":"EnglishPod_301-365","permalink":"/English/EnglishPod/EnglishPod_301-365/","createTime":"2026/06/30 08:03:42","description":"P301-310 [301] The Weekend - Vampires A: You want to go tothe movies tonight? B: Sure! What’s playing? A: The new Twilight movie! B: Twilight? As inthe vampire movies? No way I ...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"EnglishPod_301-365\\",\\"image\\":[\\"\\"],\\"dateModified\\":null,\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://docs.threekd.com/English/EnglishPod/EnglishPod_301-365/"}],["meta",{"property":"og:site_name","content":"Di's Docs"}],["meta",{"property":"og:title","content":"EnglishPod_301-365"}],["meta",{"property":"og:description","content":"P301-310 [301] The Weekend - Vampires A: You want to go tothe movies tonight? B: Sure! What’s playing? A: The new Twilight movie! B: Twilight? As inthe vampire movies? No way I ..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}]]},"git":{"createdTime":1782779198000},"autoDesc":true,"filePathRelative":"English/EnglishPod/EnglishPod_301-365.md","headers":[]}`);export{l as comp,p as data};
